@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam classBorderColor #222222
skinparam classBackgroundColor #F3F3F3
skinparam classHeaderBackgroundColor #F3F3F3
skinparam classFontSize 28
skinparam classAttributeFontSize 28
skinparam classStereotypeFontSize 28

class NetworkService {
  // bind_host是外部应用可以访问ES集群的地址
  + InetAddress[] resolveBindHostAddresses(String bindHosts[])
  // publish_host是集群内部节点通信的地址
  + InetAddress resolvePublishHostAddresses(String publishHosts[])
}
@enduml
